import ldap

def search_users_by_username(ldap_server, bind_dn, bind_password, base_dn, username):
    try:
        # Connect to the LDAP server
        conn = ldap.initialize(ldap_server)
        conn.protocol_version = 3
        conn.simple_bind_s(bind_dn, bind_password)
        
        # Search for users with the given username
        search_filter = f"(&(objectClass=user)(sAMAccountName={username}))"
        attributes = ['cn', 'sAMAccountName', 'mail', 'displayName']
        
        result = conn.search_s(base_dn, ldap.SCOPE_SUBTREE, search_filter, attributes)
        
        # Process and return the results
        users = []
        for dn, entry in result:
            if entry:
                user_info = {
                    'dn': dn,
                    'cn': entry.get('cn', [b''])[0].decode('utf-8') if entry.get('cn') else '',
                    'sAMAccountName': entry.get('sAMAccountName', [b''])[0].decode('utf-8') if entry.get('sAMAccountName') else '',
                    'mail': entry.get('mail', [b''])[0].decode('utf-8') if entry.get('mail') else '',
                    'displayName': entry.get('displayName', [b''])[0].decode('utf-8') if entry.get('displayName') else ''
                }
                users.append(user_info)
        
        conn.unbind_s()
        return users
        
    except ldap.INVALID_CREDENTIALS:
        raise Exception("Invalid credentials")
    except ldap.NO_SUCH_OBJECT:
        raise Exception("Base DN not found")
    except Exception as e:
        raise Exception(f"LDAP search failed: {str(e)}")